1	const scaleRowHorizontally = (row: string, scale: number): string =>
2	  [...row].map((pixel) => pixel.repeat(scale)).join("");
3	
4	export const scalePixelArt = (image: string[], scale: number): string[] =>
5	  image.flatMap((row) => Array(scale).fill(scaleRowHorizontally(row, scale)));
