1	import { describe, it, expect } from "vitest";
2	import { scalePixelArt } from "./pixel-art-scaler.js";
3	
4	describe("Pixel Art Scaler", () => {
5	  it("should return an empty image for an empty input regardless of scale", () => {
6	    expect(scalePixelArt([], 3)).toEqual([]);
7	  });
8	  it("should return an exact copy of the input when scale is 1", () => {
9	    expect(scalePixelArt(["#"], 1)).toEqual(["#"]);
10	  });
11	  it("should replicate a single pixel horizontally by the scale factor", () => {
12	    expect(scalePixelArt(["#"], 2)[0]).toEqual("##");
13	  });
14	  it("should replicate a single-row image vertically by the scale factor", () => {
15	    expect(scalePixelArt(["#"], 3)).toEqual(["###", "###", "###"]);
16	  });
17	  it("should scale a single pixel in both dimensions by the scale factor", () => {
18	    expect(scalePixelArt(["X"], 2)).toEqual(["XX", "XX"]);
19	  });
20	  it("should scale a multi-pixel row horizontally preserving pixel order", () => {
21	    expect(scalePixelArt(["AB"], 2)).toEqual(["AABB", "AABB"]);
22	  });
23	  it("should scale a multi-row image vertically preserving row order", () => {
24	    expect(scalePixelArt(["A", "B"], 2)).toEqual(["AA", "AA", "BB", "BB"]);
25	  });
26	  it("should scale a multi-row multi-pixel image in both dimensions", () => {
27	    expect(scalePixelArt(["AB", "CD"], 2)).toEqual(["AABB", "AABB", "CCDD", "CCDD"]);
28	  });
29	});
